// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getAllRiders,
  getCaptains,
  getPendingCaptains,
  getAllRides,
  approveRider,
  rejectRider,
  getSOSAlerts,
  resolveSOS,
} from "../../services/api";
import { useAuth } from "../../contexts/AuthContext";
import {
  AppBar,
  Toolbar,
  Box,
  Typography,
  Button,
  CircularProgress,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Card,
  CardMedia,
  CardActions,
  Grid,
  Paper,
  Tabs,
  Tab,
  Stack,
  Link,
  Dialog,
  DialogTitle,
  DialogContent,
} from "@mui/material";

import GroupsIcon from "@mui/icons-material/Groups";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import HourglassTopIcon from "@mui/icons-material/HourglassTop";
import CommuteIcon from "@mui/icons-material/Commute";
import PersonIcon from "@mui/icons-material/Person";
import WarningAmberIcon from "@mui/icons-material/WarningAmber";

export default function AdminDashboard() {
  const { logout } = useAuth();

  const [overview, setOverview] = useState({
    users: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
    riders: 0,
    sos: 0,
  });

  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Documents modal state
  const [openDocsModal, setOpenDocsModal] = useState(false);
  const [selectedDocuments, setSelectedDocuments] = useState([]);
  const [selectedRider, setSelectedRider] = useState(null);

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data.data);

      const sosRes = await getSOSAlerts();
      setOverview((prev) => ({
        ...prev,
        sos: sosRes.data?.data?.filter((s) => s.status === "active").length || 0,
      }));
    } catch (err) {
      console.error(err);
      setError("Failed to load overview");
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch (type) {
        case "users":
        case "riders":
          res = await getAllRiders();
          break;
        case "captains":
          res = await getCaptains();
          break;
        case "pending":
          res = await getPendingCaptains();
          break;
        case "rides":
          res = await getAllRides();
          break;
        case "sos":
          res = await getSOSAlerts();
          break;
        default:
          res = { data: { data: [] } };
      }
      setData(res?.data?.data || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data");
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    try {
      await approveRider(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to approve rider");
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectRider(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to reject rider");
    }
  };

  const handleResolveSOS = async (id) => {
    try {
      await resolveSOS(id);
      fetchData("sos");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to resolve SOS");
    }
  };

  const handleViewDocuments = (rider) => {
    setSelectedRider(rider);
    let docs = rider.documents || [];
    if (!Array.isArray(docs)) docs = Object.values(docs);
    setSelectedDocuments(docs);
    setOpenDocsModal(true);
  };

  const handleCloseDocuments = () => {
    setSelectedRider(null);
    setSelectedDocuments([]);
    setOpenDocsModal(false);
  };

  useEffect(() => {
    fetchOverview();
  }, []);

  const cards = [
    { label: "Users", value: overview.users, icon: <GroupsIcon />, type: "users", color: "#3498db" },
    { label: "Riders", value: overview.riders, icon: <PersonIcon />, type: "riders", color: "#1abc9c" },
    { label: "Approved Captains", value: overview.captains, icon: <VerifiedUserIcon />, type: "captains", color: "#2ecc71" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <HourglassTopIcon />, type: "pending", color: "#e67e22" },
    { label: "Rides", value: overview.rides, icon: <CommuteIcon />, type: "rides", color: "#9b59b6" },
    { label: "SOS Alerts", value: overview.sos, icon: <WarningAmberIcon />, type: "sos", color: "#e74c3c" },
  ];

  const renderDocumentsCell = (rider) => {
    if (!rider.documents || Object.keys(rider.documents).length === 0) return "-";
    return (
      <Button variant="outlined" size="small" onClick={() => handleViewDocuments(rider)}>
        View Documents
      </Button>
    );
  };

  const renderActionsCell = (item) => (
    <Stack direction="row" spacing={1} justifyContent="center">
      <Button size="small" color="success" variant="outlined" onClick={() => handleApprove(item._id)}>
        Approve
      </Button>
      <Button size="small" color="error" variant="outlined" onClick={() => handleReject(item._id)}>
        Reject
      </Button>
    </Stack>
  );

  return (
    <Box sx={{ flexGrow: 1, bgcolor: "#f4f6f8", minHeight: "100vh" }}>
      <AppBar position="static" sx={{ bgcolor: "#34495e", mb: 4 }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
          <Typography variant="h6" fontWeight="bold">Admin Dashboard</Typography>
          <Button variant="contained" color="error" onClick={logout}>Logout</Button>
        </Toolbar>
      </AppBar>

      <Box maxWidth="1300px" mx="auto" px={3} pb={5}>
        <Paper elevation={3} sx={{ borderRadius: 3, mb: 4 }}>
          <Tabs
            value={activeTab}
            onChange={(e, val) => {
              setData([]);
              val === "overview" ? fetchOverview() : fetchData(val);
              setActiveTab(val);
            }}
            indicatorColor="primary"
            textColor="primary"
            variant="fullWidth"
            sx={{ "& .MuiTab-root": { fontWeight: 600, fontSize: "14px" } }}
          >
            <Tab label="Overview" value="overview" />
            <Tab label="Users" value="users" />
            <Tab label="Riders" value="riders" />
            <Tab label="Approved Captains" value="captains" />
            <Tab label="Pending Captains" value="pending" />
            <Tab label="Rides" value="rides" />
            <Tab label="SOS Alerts" value="sos" />
          </Tabs>
        </Paper>

        {activeTab === "overview" && (
          <Grid container spacing={3}>
            {cards.map((card) => (
              <Grid item xs={12} sm={6} md={3} key={card.label}>
                <Card
                  sx={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    p: 2,
                    borderRadius: 3,
                    boxShadow: 3,
                    transition: "0.3s",
                    "&:hover": { boxShadow: 6, transform: "translateY(-5px)" },
                  }}
                  onClick={() => card.type !== "overview" && fetchData(card.type)}
                >
                  <Box>
                    <Typography variant="subtitle1" fontWeight="bold" color={card.color}>{card.label}</Typography>
                    <Typography variant="h4" fontWeight="bold" color={card.color}>{card.value}</Typography>
                  </Box>
                  <Box sx={{ fontSize: 50, color: card.color }}>{card.icon}</Box>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}

        {loading && <Box display="flex" justifyContent="center" mt={4}><CircularProgress /></Box>}
        {error && <Typography color="error" textAlign="center" mt={2}>{error}</Typography>}

        {!loading && data.length > 0 && activeTab !== "overview" && activeTab !== "sos" && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 3, mt: 4, overflowX: "auto" }}>
            <Typography variant="h6" mb={2} fontWeight="bold">{activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} Details</Typography>
            <Table>
              <TableHead>
                <TableRow sx={{ bgcolor: "#ecf0f1" }}>
                  <TableCell sx={{ fontWeight: 600 }}>Name</TableCell>
                  <TableCell sx={{ fontWeight: 600 }}>Email</TableCell>
                  <TableCell sx={{ fontWeight: 600 }}>Mobile</TableCell>
                  <TableCell sx={{ fontWeight: 600 }}>Role</TableCell>
                  {(activeTab === "captains" || activeTab === "pending") && <TableCell sx={{ fontWeight: 600 }}>Documents</TableCell>}
                  {activeTab === "pending" && <TableCell sx={{ fontWeight: 600, textAlign: "center" }}>Actions</TableCell>}
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((rider) => (
                  <TableRow key={rider._id} hover sx={{ "&:nth-of-type(odd)": { bgcolor: "#fafafa" } }}>
                    <TableCell>{rider.fullName}</TableCell>
                    <TableCell>{rider.email}</TableCell>
                    <TableCell>{rider.mobile}</TableCell>
                    <TableCell>{rider.role}</TableCell>
                    {(activeTab === "captains" || activeTab === "pending") && (
                      <TableCell>{renderDocumentsCell(rider)}</TableCell>
                    )}
                    {activeTab === "pending" && <TableCell align="center">{renderActionsCell(rider)}</TableCell>}
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}

        {/* Documents Modal */}
        <Dialog open={openDocsModal} onClose={handleCloseDocuments} maxWidth="md" fullWidth>
          <DialogTitle>Rider Details {selectedRider?.fullName ? `- ${selectedRider.fullName}` : ""}</DialogTitle>
          <DialogContent dividers>
            {selectedRider && (
              <Box mb={3}>
                <Typography><strong>Name:</strong> {selectedRider.fullName}</Typography>
                <Typography><strong>Email:</strong> {selectedRider.email}</Typography>
                <Typography><strong>Mobile:</strong> {selectedRider.mobile}</Typography>
                <Typography><strong>Role:</strong> {selectedRider.role}</Typography>
                <Typography><strong>Status:</strong> {selectedRider.approvalStatus || "-"}</Typography>
                <Typography><strong>Created At:</strong> {selectedRider.createdAt ? new Date(selectedRider.createdAt).toLocaleString() : "-"}</Typography>
              </Box>
            )}

            <Typography variant="h6" gutterBottom>Documents</Typography>

            {(!selectedDocuments || selectedDocuments.length === 0) ? (
              <Typography>No documents uploaded.</Typography>
            ) : (
              <Stack spacing={2} direction="row" flexWrap="wrap">
                {selectedDocuments.map((doc, idx) => {
                  const url = doc?.url || doc?.location || doc?.secure_url || doc?.path || doc;
                  const isImage = /\.(jpe?g|png|gif|webp)$/i.test(url || "");
                  return (
                    <Card key={idx} sx={{ width: 250 }}>
                      {isImage ? (
                        <CardMedia component="img" height="180" image={url} alt={`Document ${idx + 1}`} sx={{ objectFit: "contain" }} />
                      ) : (
                        <Box sx={{ height: 180, display: "flex", alignItems: "center", justifyContent: "center", bgcolor: "#f5f5f5" }}>
                          <Typography>Document {idx + 1}</Typography>
                        </Box>
                      )}
                      <CardActions>
                        <Button size="small" onClick={() => window.open(url, "_blank")}>View</Button>
                      </CardActions>
                    </Card>
                  );
                })}
              </Stack>
            )}
          </DialogContent>
        </Dialog>
      </Box>
    </Box>
  );
}
